data:
{
  "评审条款": [
    {
      "条款编号": "2.1.1",
      "描述": "形式评审标准",
      "内容": [
        {
          "子项": "投标人名称",
          "要求": "与营业执照（事业单位法人证书）资质证书一致"
        },
        {
          "子项": "独立法人与制造商资格",
          "要求": "投标人须为在中华人民共和国境内注册的独立法人，且须为开关柜柜体类产品制造商"
        }
      ],
      "分值": null,
      "权重": null
    },
    {
      "条款编号": "2.1.2",
      "描述": "资格评审标准",
      "内容": [
        {
          "子项": "业绩",
          "要求": "自2019年以来，投标人须至少具有所投类似产品（开关柜）3份销售业绩，并提供合同复印件，合同复印件至少应包括合同首页、内容页、签字页或盖章页，应能体现出供货范围（单笔合同供货数量须满足（KYN28柜或KYN61柜累计不少于50台）或（MNS柜不少于80台）），合同原件备查"
        },
        {
          "子项": "证书",
          "要求": "投标人须通过质量、环境、职业健康体系认证，且在有效期内，须提供证书扫描件"
        }
      ],
      "分值": null,
      "权重": null
    },
    {
      "条款编号": "2.1.3",
      "描述": "响应性评审标准",
      "内容": [
        {
          "子项": "商务响应",
          "要求": "是否实质性响应投标响应期、保证金、供货期限等实质性商务要求。投标保证金的金额：人民币8万元"
        }
      ],
      "分值": null,
      "权重": null
    }
  ],
  "评分标准": [
    {
      "条款编号": "2.2.1",
      "描述": "分值构成（总分100分）",
      "内容": [
        {
          "评分项": "商务部分",
          "分值": 30,
          "权重": 0.3
        },
        {
          "评分项": "技术部分",
          "分值": 30,
          "权重": 0.3
        },
        {
          "评分项": "投标报价",
          "分值": 40,
          "权重": 0.4
        },
        {
          "评分项": "其他评分因素",
          "分值": 0,
          "权重": 0.0
        }
      ]
    },
    {
      "条款编号": "2.2.2",
      "描述": "评标基准价计算方法",
      "内容": "经评审的有效投标报价中最低价作为评标基准价（评标基准价精确至小数点后两位）",
      "分值": null,
      "权重": null
    },
    {
      "条款编号": "2.2.3",
      "描述": "投标报价的偏差率计算公式",
      "内容": "偏差率 = (评标价 - 评标基准价) / 评标基准价 × 100%",
      "分值": null,
      "权重": null
    }
  ],
  "评分细则": [
    {
      "条款编号": "2.2.4(1)",
      "类别": "商务评分",
      "评分项": "企业信誉及综合实力",
      "分值": 10,
      "评分标准": "对投标人的企业信誉及综合实力进行横向比较，优得10分，良得3-9分，一般的得2分。需提供营业执照、企业简介、财务报表、人员配备等体现企业信誉及综合实力的相关证明材料"
    },
    {
      "条款编号": "2.2.4(1)",
      "类别": "商务评分",
      "评分项": "商务响应程度",
      "分值": 10,
      "评分标准": "满足招标文件中付款条件等商务条款要求得8分，有负偏离酌情扣分、最低得0分，优于招标文件要求的情加，最多加2分"
    },
    {
      "条款编号": "2.2.4(1)",
      "类别": "商务评分",
      "评分项": "业绩",
      "分值": 10,
      "评分标准": "自2019年以来，在满足资格要求业绩数量基础上，每多提供1份得1分，最高得10分。需提供合同复印件（含首页、内容页、签字/盖章页），体现供货范围（KYN28/KYN61柜累计≥50台 或 MNS柜≥80台），以合同复印件为准"
    },
    {
      "条款编号": "2.2.4(2)",
      "类别": "技术评分",
      "评分项": "产品技术性能",
      "分值": 16,
      "评分标准": "满足招标文件要求（包括外壳防护等级不低于IP41的设计方案和措施、提供柜体配套使用的接地开关、母线套管、熔头盒等关键配件的型式试验报告）得10分，有负偏离酌情扣分，最低得5分，优于要求可加分，最多加5分"
    },
    {
      "条款编号": "2.2.4(2)",
      "类别": "技术评分",
      "评分项": "产品试验报告与技术说明书",
      "分值": 7.5,
      "评分标准": "投标人须分别提供所投MNS、KYN28、KYN61三类开关柜产品整机试验报告和技术说明书，每提供一类得2.5分，最多得7.5分"
    },
    {
      "条款编号": "2.2.4(2)",
      "类别": "技术评分",
      "评分项": "质量保证",
      "分值": 7,
      "评分标准": "企业有先进的生产加工装备，有切实可行的质量监督和检查措施；有健全的质量管理组织机构，有较好的质量技术团队，得3分；企业通过质量体系认证的，加1分；能够提供投标产品专利的，每份加1分，最多加2分；能够提供投标产品有市级及以上产品质量获奖证明的，每份加1分，最多加1分"
    },
    {
      "条款编号": "2.2.4(2)",
      "类别": "技术评分",
      "评分项": "售后服务",
      "分值": 7,
      "评分标准": "有完善的售后服务措施和健全的组织机构得5-7分；有较完善的售后服务措施和健全的组织机构得1-4分；售后服务有不良记录的，得0分"
    },
    {
      "条款编号": "2.2.4(3)",
      "类别": "投标报价评分",
      "评分项": "投标报价得分",
      "分值": 40,
      "评分标准": "评标价等于评标基准值得基础分40分；高于评标基准价1%，在基础分上扣1分；最低得分为30分；不足1%的，按直线插入法计算，得分保留两位小数"
    },
    {
      "条款编号": "3.13",
      "类别": "其他因素",
      "评分项": "缺漏项处理",
      "分值": null,
      "评分标准": "1. 缺漏项 ≥ 投标总价10% 的，投标将被否决；2. 缺漏项 < 投标总价10% 的，视为价格已包含在其他分项报价中，投标人应书面澄清确认，拒不澄清确认的，投标将被否决"
    }
  ]
}
